UPDATE words SET example_en_2 = 'The scientist formed a hypothesis before the experiment.', example_ko_2 = '과학자는 실험 전에 가설을 세웠어요.', example_en_3 = 'Her hypothesis was proven correct by the data.', example_ko_3 = '그녀의 가설은 데이터에 의해 옳다고 증명됐어요.', example_en_4 = 'Write your hypothesis clearly before you begin.', example_ko_4 = '시작하기 전에 가설을 명확하게 써 주세요.', example_en_5 = 'The hypothesis was rejected after the results came in.', example_ko_5 = '결과가 나온 후 가설은 기각됐어요.' WHERE id = 'w_academic_B1_01';

UPDATE words SET example_en_2 = 'There is strong evidence that exercise improves memory.', example_ko_2 = '운동이 기억력을 향상시킨다는 강력한 증거가 있어요.', example_en_3 = 'The police found new evidence at the scene.', example_ko_3 = '경찰은 현장에서 새로운 증거를 발견했어요.', example_en_4 = 'You need evidence to support your argument.', example_ko_4 = '주장을 뒷받침하기 위한 증거가 필요해요.', example_en_5 = 'The court dismissed the case due to lack of evidence.', example_ko_5 = '법원은 증거 부족으로 사건을 기각했어요.' WHERE id = 'w_academic_B1_02';

UPDATE words SET example_en_2 = 'The students were asked to analyze a short poem.', example_ko_2 = '학생들은 짧은 시를 분석하도록 요청받았어요.', example_en_3 = 'He analyzed the survey results using a spreadsheet.', example_ko_3 = '그는 스프레드시트를 사용해 설문 조사 결과를 분석했어요.', example_en_4 = 'Analyze the causes of the problem before proposing solutions.', example_ko_4 = '해결책을 제시하기 전에 문제의 원인을 분석해 주세요.', example_en_5 = 'She analyzed the text and identified the main themes.', example_ko_5 = '그녀는 텍스트를 분석하고 주요 주제를 파악했어요.' WHERE id = 'w_academic_B1_03';

UPDATE words SET example_en_2 = 'From the evidence, we can conclude that pollution is increasing.', example_ko_2 = '증거로부터 오염이 증가하고 있다고 결론 내릴 수 있어요.', example_en_3 = 'The report concluded that the program was successful.', example_ko_3 = '보고서는 프로그램이 성공적이었다고 결론지었어요.', example_en_4 = 'It is too early to conclude anything from these results.', example_ko_4 = '이 결과로 어떤 결론을 내리기에는 너무 이른 시간이에요.', example_en_5 = 'He concluded the presentation with a summary.', example_ko_5 = '그는 요약으로 발표를 마무리했어요.' WHERE id = 'w_academic_B1_04';

UPDATE words SET example_en_2 = 'Remember to cite every source you use.', example_ko_2 = '사용하는 모든 출처를 인용하는 것을 잊지 마세요.', example_en_3 = 'She cited three academic articles in her paper.', example_ko_3 = '그녀는 논문에서 세 개의 학술 기사를 인용했어요.', example_en_4 = 'It is considered dishonest not to cite your sources.', example_ko_4 = '출처를 인용하지 않는 것은 부정직하다고 여겨져요.', example_en_5 = 'The essay guidelines require you to cite in APA format.', example_ko_5 = '에세이 지침은 APA 형식으로 인용하도록 요구해요.' WHERE id = 'w_academic_B1_05';

UPDATE words SET example_en_2 = 'The abstract gave a clear overview of the study.', example_ko_2 = '초록은 연구에 대한 명확한 개요를 제공했어요.', example_en_3 = 'Write the abstract after you finish the full paper.', example_ko_3 = '전체 논문을 완성한 후에 초록을 작성해 주세요.', example_en_4 = 'The abstract should be no more than 250 words.', example_ko_4 = '초록은 250단어를 넘지 않아야 해요.', example_en_5 = 'He read the abstract first to decide if the paper was relevant.', example_ko_5 = '그는 논문이 관련 있는지 확인하기 위해 먼저 초록을 읽었어요.' WHERE id = 'w_academic_B1_06';

UPDATE words SET example_en_2 = 'The journal publishes articles on language education.', example_ko_2 = '그 학술지는 언어 교육에 관한 기사를 게재해요.', example_en_3 = 'I found the article in an academic journal online.', example_ko_3 = '온라인 학술지에서 기사를 찾았어요.', example_en_4 = 'She keeps a personal journal to reflect on her learning.', example_ko_4 = '그녀는 학습을 성찰하기 위해 개인 일지를 작성해요.', example_en_5 = 'Papers submitted to this journal go through peer review.', example_ko_5 = '이 학술지에 제출된 논문은 동료 심사를 거쳐요.' WHERE id = 'w_academic_B1_07';

UPDATE words SET example_en_2 = 'This empirical study used data from 500 participants.', example_ko_2 = '이 경험적 연구는 500명의 참가자 데이터를 사용했어요.', example_en_3 = 'Empirical evidence is essential in scientific research.', example_ko_3 = '경험적 증거는 과학적 연구에서 필수적이에요.', example_en_4 = 'The empirical approach relies on observation, not theory alone.', example_ko_4 = '경험적 접근법은 이론만이 아닌 관찰에 의존해요.', example_en_5 = 'They conducted empirical tests to verify the claims.', example_ko_5 = '그들은 주장을 검증하기 위해 경험적 테스트를 실시했어요.' WHERE id = 'w_academic_B1_08';

UPDATE words SET example_en_2 = 'The independent variable was the amount of sleep.', example_ko_2 = '독립 변수는 수면 시간이었어요.', example_en_3 = 'Keep all other variables constant during the experiment.', example_ko_3 = '실험 중에 다른 모든 변수를 일정하게 유지해 주세요.', example_en_4 = 'Temperature was the key variable in this study.', example_ko_4 = '온도가 이 연구의 핵심 변수였어요.', example_en_5 = 'They identified three main variables that affected the results.', example_ko_5 = '그들은 결과에 영향을 미친 세 가지 주요 변수를 파악했어요.' WHERE id = 'w_academic_B1_09';

UPDATE words SET example_en_2 = 'The methodology section explained how data was collected.', example_ko_2 = '방법론 섹션은 데이터가 어떻게 수집됐는지 설명했어요.', example_en_3 = 'A clear methodology makes it easier to replicate the study.', example_ko_3 = '명확한 방법론은 연구를 재현하기 더 쉽게 만들어요.', example_en_4 = 'She chose a qualitative methodology for her research.', example_ko_4 = '그녀는 연구를 위해 질적 방법론을 선택했어요.', example_en_5 = 'The professor asked the student to justify their methodology.', example_ko_5 = '교수님은 학생에게 방법론을 정당화하도록 요청했어요.' WHERE id = 'w_academic_B1_10';

UPDATE words SET example_en_2 = 'Your argument needs to be more clearly structured.', example_ko_2 = '주장이 더 명확하게 구조화되어야 해요.', example_en_3 = 'The essay presents a well-reasoned argument.', example_ko_3 = '에세이는 잘 추론된 논증을 제시해요.', example_en_4 = 'She built her argument on three key pieces of evidence.', example_ko_4 = '그녀는 세 가지 핵심 증거를 바탕으로 논증을 구축했어요.', example_en_5 = 'A strong argument requires both logic and evidence.', example_ko_5 = '강력한 논증은 논리와 증거가 모두 필요해요.' WHERE id = 'w_academic_B1_11';

UPDATE words SET example_en_2 = 'We will evaluate each proposal next week.', example_ko_2 = '다음 주에 각 제안서를 평가할 거예요.', example_en_3 = 'She evaluated the reliability of each source carefully.', example_ko_3 = '그녀는 각 출처의 신뢰도를 주의 깊게 평가했어요.', example_en_4 = 'The professor will evaluate essays based on clarity and logic.', example_ko_4 = '교수님은 명확성과 논리를 기준으로 에세이를 평가할 거예요.', example_en_5 = 'Evaluate both strengths and weaknesses in your analysis.', example_ko_5 = '분석에서 강점과 약점을 모두 평가해 주세요.' WHERE id = 'w_academic_B1_12';

UPDATE words SET example_en_2 = 'How do you interpret this graph?', example_ko_2 = '이 그래프를 어떻게 해석하시나요?', example_en_3 = 'The results can be interpreted in several ways.', example_ko_3 = '결과는 여러 방식으로 해석될 수 있어요.', example_en_4 = 'She interpreted the data as showing a positive trend.', example_ko_4 = '그녀는 데이터를 긍정적인 추세를 보여주는 것으로 해석했어요.', example_en_5 = 'It is easy to misinterpret data without proper context.', example_ko_5 = '적절한 맥락 없이는 데이터를 오해하기 쉬워요.' WHERE id = 'w_academic_B1_13';

UPDATE words SET example_en_2 = 'The improvement in test scores was significant.', example_ko_2 = '시험 점수의 향상은 유의미했어요.', example_en_3 = 'Exercise has a significant effect on mental health.', example_ko_3 = '운동은 정신 건강에 유의미한 영향을 미쳐요.', example_en_4 = 'She made a significant contribution to the project.', example_ko_4 = '그녀는 프로젝트에 유의미한 기여를 했어요.', example_en_5 = 'There is no statistically significant difference between the groups.', example_ko_5 = '그룹 간에 통계적으로 유의미한 차이가 없어요.' WHERE id = 'w_academic_B1_14';

UPDATE words SET example_en_2 = 'Researchers found a positive correlation between income and education.', example_ko_2 = '연구자들은 소득과 교육 사이에 양의 상관관계를 발견했어요.', example_en_3 = 'The correlation between the two variables was weak.', example_ko_3 = '두 변수 사이의 상관관계는 약했어요.', example_en_4 = 'Is there a correlation between diet and academic performance?', example_ko_4 = '식단과 학업 성적 사이에 상관관계가 있나요?', example_en_5 = 'The chart clearly shows a strong positive correlation.', example_ko_5 = '차트는 강한 양의 상관관계를 명확하게 보여줘요.' WHERE id = 'w_academic_B1_15';

UPDATE words SET example_en_2 = 'An objective assessment removes personal bias.', example_ko_2 = '객관적인 평가는 개인적 편향을 제거해요.', example_en_3 = 'Try to be objective when reviewing your own work.', example_ko_3 = '자신의 작업을 검토할 때 객관적으로 유지하려고 노력해 주세요.', example_en_4 = 'It is difficult to remain objective when the topic is personal.', example_ko_4 = '주제가 개인적일 때 객관적을 유지하기 어려워요.', example_en_5 = 'She gave an objective review of the research.', example_ko_5 = '그녀는 연구에 대한 객관적인 검토를 제공했어요.' WHERE id = 'w_academic_B1_16';

UPDATE words SET example_en_2 = 'Art criticism is inherently subjective.', example_ko_2 = '미술 비평은 본질적으로 주관적이에요.', example_en_3 = 'His evaluation was too subjective to be useful.', example_ko_3 = '그의 평가는 너무 주관적이어서 유용하지 않았어요.', example_en_4 = 'Beauty is subjective — different people see it differently.', example_ko_4 = '아름다움은 주관적이에요. 사람마다 다르게 봐요.', example_en_5 = 'The grading rubric reduces the chance of subjective marking.', example_ko_5 = '채점 기준표는 주관적 채점의 가능성을 줄여줘요.' WHERE id = 'w_academic_B1_17';

UPDATE words SET example_en_2 = 'Define the term before using it in your essay.', example_ko_2 = '에세이에서 사용하기 전에 용어를 정의해 주세요.', example_en_3 = 'The textbook defines the concept clearly.', example_ko_3 = '교과서는 개념을 명확하게 정의해요.', example_en_4 = 'It is difficult to define "intelligence" precisely.', example_ko_4 = '"지능"을 정확하게 정의하기는 어려워요.', example_en_5 = 'She defined the scope of her research in the introduction.', example_ko_5 = '그녀는 서론에서 연구 범위를 정의했어요.' WHERE id = 'w_academic_B1_18';

UPDATE words SET example_en_2 = 'The concept of democracy is complex.', example_ko_2 = '민주주의의 개념은 복잡해요.', example_en_3 = 'She had trouble grasping the concept at first.', example_ko_3 = '그녀는 처음에 개념을 파악하는 데 어려움이 있었어요.', example_en_4 = 'The teacher used examples to explain the concept.', example_ko_4 = '선생님은 개념을 설명하기 위해 예시를 사용했어요.', example_en_5 = 'This concept underpins the entire research project.', example_ko_5 = '이 개념은 전체 연구 프로젝트의 기초가 돼요.' WHERE id = 'w_academic_B1_19';

UPDATE words SET example_en_2 = 'The research framework guides all stages of the study.', example_ko_2 = '연구 틀은 연구의 모든 단계를 안내해요.', example_en_3 = 'She chose a social constructivist framework.', example_ko_3 = '그녀는 사회 구성주의 틀을 선택했어요.', example_en_4 = 'Without a clear framework, the study lacks direction.', example_ko_4 = '명확한 틀 없이는 연구에 방향이 부족해요.', example_en_5 = 'They applied a cognitive framework to interpret the findings.', example_ko_5 = '그들은 연구 결과를 해석하기 위해 인지적 틀을 적용했어요.' WHERE id = 'w_academic_B1_20';

UPDATE words SET example_en_2 = 'She took a critical look at the author''s assumptions.', example_ko_2 = '그녀는 저자의 가정을 비판적으로 살펴봤어요.', example_en_3 = 'Critical reading is an essential academic skill.', example_ko_3 = '비판적 독서는 필수적인 학술 기술이에요.', example_en_4 = 'Be critical but constructive when giving feedback.', example_ko_4 = '피드백을 줄 때 비판적이지만 건설적으로 해 주세요.', example_en_5 = 'He raised critical questions about the methodology.', example_ko_5 = '그는 방법론에 대한 비판적인 질문을 제기했어요.' WHERE id = 'w_academic_B1_21';

UPDATE words SET example_en_2 = 'The implications of this study are wide-ranging.', example_ko_2 = '이 연구의 함의는 광범위해요.', example_en_3 = 'Consider the policy implications of your findings.', example_ko_3 = '연구 결과의 정책적 함의를 고려해 주세요.', example_en_4 = 'The implication is that more research is needed.', example_ko_4 = '함의는 더 많은 연구가 필요하다는 거예요.', example_en_5 = 'She explained the practical implications for teachers.', example_ko_5 = '그녀는 교사들을 위한 실질적 함의를 설명했어요.' WHERE id = 'w_academic_B1_22';

UPDATE words SET example_en_2 = 'Only include information relevant to the research question.', example_ko_2 = '연구 질문과 관련 있는 정보만 포함해 주세요.', example_en_3 = 'That example is not relevant to the current topic.', example_ko_3 = '그 예시는 현재 주제와 관련이 없어요.', example_en_4 = 'Is this article relevant to your essay?', example_ko_4 = '이 기사가 에세이와 관련이 있나요?', example_en_5 = 'She selected only the most relevant sources for her paper.', example_ko_5 = '그녀는 논문을 위해 가장 관련 있는 출처만 선택했어요.' WHERE id = 'w_academic_B1_23';

UPDATE words SET example_en_2 = 'I used five references in my essay.', example_ko_2 = '에세이에서 다섯 개의 참고 문헌을 사용했어요.', example_en_3 = 'Check your references carefully before submitting.', example_ko_3 = '제출 전에 참고 문헌을 주의 깊게 확인해 주세요.', example_en_4 = 'This reference is from a reliable academic journal.', example_ko_4 = '이 참고 문헌은 신뢰할 수 있는 학술지에서 왔어요.', example_en_5 = 'He made a reference to an earlier study on the same topic.', example_ko_5 = '그는 같은 주제에 관한 이전 연구를 참고 문헌으로 언급했어요.' WHERE id = 'w_academic_B1_24';

UPDATE words SET example_en_2 = 'The data collected over ten years showed a clear trend.', example_ko_2 = '10년에 걸쳐 수집된 데이터는 명확한 추세를 보여줬어요.', example_en_3 = 'We need more data before drawing any conclusions.', example_ko_3 = '어떤 결론을 내리기 전에 더 많은 데이터가 필요해요.', example_en_4 = 'The data was analyzed using statistical software.', example_ko_4 = '데이터는 통계 소프트웨어를 사용해 분석됐어요.', example_en_5 = 'All the data was stored securely on a university server.', example_ko_5 = '모든 데이터는 대학교 서버에 안전하게 저장됐어요.' WHERE id = 'w_academic_B1_25';

UPDATE words SET example_en_2 = 'A random sample reduces the chance of bias.', example_ko_2 = '무작위 표본은 편향의 가능성을 줄여요.', example_en_3 = 'The sample consisted of students aged 18 to 25.', example_ko_3 = '표본은 18세에서 25세 사이의 학생들로 구성됐어요.', example_en_4 = 'We need a larger sample to generalize the findings.', example_ko_4 = '결과를 일반화하기 위해 더 큰 표본이 필요해요.', example_en_5 = 'She explained how she selected the sample.', example_ko_5 = '그녀는 표본을 어떻게 선택했는지 설명했어요.' WHERE id = 'w_academic_B1_26';

UPDATE words SET example_en_2 = 'The survey asked about reading habits and frequency.', example_ko_2 = '설문 조사는 독서 습관과 빈도에 대해 물었어요.', example_en_3 = 'Respondents answered the survey anonymously.', example_ko_3 = '응답자들은 익명으로 설문 조사에 답했어요.', example_en_4 = 'She analyzed the survey data using charts and graphs.', example_ko_4 = '그녀는 차트와 그래프를 사용해 설문 조사 데이터를 분석했어요.', example_en_5 = 'The survey results showed that most students prefer group work.', example_ko_5 = '설문 조사 결과는 대부분의 학생이 그룹 활동을 선호한다고 나타났어요.' WHERE id = 'w_academic_B1_27';

UPDATE words SET example_en_2 = 'The experiment demonstrated that caffeine affects focus.', example_ko_2 = '실험은 카페인이 집중력에 영향을 미친다는 것을 증명했어요.', example_en_3 = 'She demonstrated her argument with a clear example.', example_ko_3 = '그녀는 명확한 예시로 주장을 증명했어요.', example_en_4 = 'The teacher demonstrated the correct technique step by step.', example_ko_4 = '선생님은 올바른 기법을 단계별로 증명했어요.', example_en_5 = 'The study demonstrates the importance of early intervention.', example_ko_5 = '연구는 조기 개입의 중요성을 증명해요.' WHERE id = 'w_academic_B1_28';

UPDATE words SET example_en_2 = 'Time was a major limitation in this study.', example_ko_2 = '시간이 이 연구의 주요 한계였어요.', example_en_3 = 'Acknowledge the limitations of your research honestly.', example_ko_3 = '연구의 한계를 솔직하게 인정해 주세요.', example_en_4 = 'The small sample size is a key limitation.', example_ko_4 = '작은 표본 크기가 주요 한계예요.', example_en_5 = 'Despite its limitations, the study provides valuable insights.', example_ko_5 = '한계에도 불구하고 연구는 귀중한 통찰력을 제공해요.' WHERE id = 'w_academic_B1_29';

UPDATE words SET example_en_2 = 'One assumption is that all participants were honest.', example_ko_2 = '한 가지 가정은 모든 참가자가 정직했다는 거예요.', example_en_3 = 'Do not make assumptions without evidence.', example_ko_3 = '증거 없이 가정을 세우지 마세요.', example_en_4 = 'State your assumptions clearly in the introduction.', example_ko_4 = '서론에서 가정을 명확하게 기술해 주세요.', example_en_5 = 'Her assumptions about the sample proved to be incorrect.', example_ko_5 = '표본에 대한 그녀의 가정이 틀린 것으로 밝혀졌어요.' WHERE id = 'w_academic_B1_30';

UPDATE words SET example_en_2 = 'Write your observations in a field notebook.', example_ko_2 = '현장 노트에 관찰 내용을 기록해 주세요.', example_en_3 = 'Her observation led to a new hypothesis.', example_ko_3 = '그녀의 관찰은 새로운 가설로 이어졌어요.', example_en_4 = 'The observation period lasted three months.', example_ko_4 = '관찰 기간은 3개월 동안 지속됐어요.', example_en_5 = 'He made careful observations during the classroom visit.', example_ko_5 = '그는 교실 방문 중에 주의 깊은 관찰을 했어요.' WHERE id = 'w_academic_B1_31';

UPDATE words SET example_en_2 = 'Researchers identified a recurring pattern in the data.', example_ko_2 = '연구자들은 데이터에서 반복되는 패턴을 파악했어요.', example_en_3 = 'Is there a pattern to when students make mistakes?', example_ko_3 = '학생들이 실수를 할 때 패턴이 있나요?', example_en_4 = 'She noticed a pattern in how vocabulary is acquired.', example_ko_4 = '그녀는 어휘가 습득되는 방식에서 패턴을 발견했어요.', example_en_5 = 'The graph shows a clear seasonal pattern.', example_ko_5 = '그래프는 명확한 계절적 패턴을 보여줘요.' WHERE id = 'w_academic_B1_32';

UPDATE words SET example_en_2 = 'From a historical perspective, this change is significant.', example_ko_2 = '역사적 관점에서 이 변화는 유의미해요.', example_en_3 = 'She offered a fresh perspective on the old theory.', example_ko_3 = '그녀는 오래된 이론에 대한 새로운 관점을 제시했어요.', example_en_4 = 'Try to see the issue from the student''s perspective.', example_ko_4 = '학생의 관점에서 문제를 바라보려고 해 주세요.', example_en_5 = 'Different perspectives enrich academic discussion.', example_ko_5 = '다양한 관점은 학술적 토론을 풍부하게 해요.' WHERE id = 'w_academic_B1_33';

UPDATE words SET example_en_2 = 'Peer pressure can have a strong influence on behavior.', example_ko_2 = '또래 압력은 행동에 강한 영향을 미칠 수 있어요.', example_en_3 = 'Her teacher''s influence inspired her to study linguistics.', example_ko_3 = '선생님의 영향이 그녀가 언어학을 공부하도록 영감을 줬어요.', example_en_4 = 'Social media has a huge influence on young learners.', example_ko_4 = '소셜 미디어는 어린 학습자들에게 큰 영향을 미쳐요.', example_en_5 = 'The study examines the influence of motivation on learning outcomes.', example_ko_5 = '연구는 동기 부여가 학습 성과에 미치는 영향을 살펴봐요.' WHERE id = 'w_academic_B1_34';

UPDATE words SET example_en_2 = 'She took a collaborative approach to the project.', example_ko_2 = '그녀는 프로젝트에 협력적 접근 방식을 취했어요.', example_en_3 = 'Which approach do you find most effective?', example_ko_3 = '어떤 접근 방식이 가장 효과적이라고 생각하나요?', example_en_4 = 'The teacher adopted a student-centered approach.', example_ko_4 = '선생님은 학생 중심 접근 방식을 채택했어요.', example_en_5 = 'A holistic approach considers all aspects of the problem.', example_ko_5 = '총체적 접근 방식은 문제의 모든 측면을 고려해요.' WHERE id = 'w_academic_B1_35';
